 65→function parseLocation(input: unknown): SubmissionLocation | null {
 66→  if (!input || typeof input !== "object") return null;
 67→  const location = input as { latitude?: unknown; longitude?: unknown };
 68→  const latitude = typeof location.latitude === "string" ? Number(location.latitude) : (location.latitude as number);
 69→  const longitude = typeof location.longitude === "string" ? Number(location.longitude) : (location.longitude as number);
 70→  if (!Number.isFinite(latitude) || !Number.isFinite(longitude)) return null;
 71→  return { latitude, longitude };
 72→}
 73→
 74→function hasValue(input: unknown): boolean {
 75→  if (typeof input === "string") return Boolean(input.trim());
 76→  if (typeof input === "boolean") return true;
 77→  if (typeof input === "number") return Number.isFinite(input);
 78→  if (Array.isArray(input)) return input.length > 0;
 79→  if (input && typeof input === "object") return Object.keys(input as object).length > 0;
 80→  return false;
 81→}
 82→
 83→function trimString(input: unknown, maxLen = 256): string | null {
 84→  if (typeof input !== "string") return null;
 85→  const value = input.trim();
 86→  if (!value) return null;
 87→  return value.slice(0, maxLen);
 88→}
