 90→function sanitizeClientDevice(input: unknown): ClientDeviceInfo | null {
 91→  if (!input || typeof input !== "object") return null;
 92→  const raw = input as Record<string, unknown>;
 93→  const deviceId = trimString(raw.deviceId, 128);
 94→  if (!deviceId) return null;
 95→  const platform = trimString(raw.platform, 64);
 96→  const userAgent = trimString(raw.userAgent, 256);
 97→  const memory = typeof raw.deviceMemoryGb === "number" && Number.isFinite(raw.deviceMemoryGb) ? raw.deviceMemoryGb : null;
 98→  const cpu = typeof raw.hardwareConcurrency === "number" && Number.isFinite(raw.hardwareConcurrency) ? raw.hardwareConcurrency : null;
 99→  const isLowEnd = raw.isLowEnd === true;
100→
101→  return {
102→    deviceId,
103→    platform: platform ?? undefined,
104→    userAgent: userAgent ?? undefined,
105→    deviceMemoryGb: memory,
106→    hardwareConcurrency: cpu,
107→    isLowEnd,
108→  };
109→}
