111→function normalizeCategory(input: string | undefined): SubmissionCategory | null {
112→  if (!input) return null;
113→  const raw = input.trim();
114→  const resolved = normalizeCategoryAlias(raw);
115→  if (resolved && isValidCategory(resolved)) return resolved as SubmissionCategory;
116→  return null;
