142→function stripInlinePhotoData(event: PointEvent): PointEvent {
143→  if (!isInlinePhotoData(event.photoUrl)) return event;
144→  const { photoUrl: _photoUrl, ...rest } = event;
145→  const details = { ...(event.details ?? {}), hasPhoto: true };
146→  return { ...rest, details };
