178→async function uploadSubmissionPhoto(
179→  eventId: string,
180→  imageBuffer: Buffer,
181→  mime: string,
182→  ext: string,
183→): Promise<string> {
184→  const pathname = `submissions/${eventId}-${Date.now()}.${ext}`;
