392→async function buildCombinedEvents(): Promise<PointEvent[]> {
393→  const pointEvents = (await getPointEvents()).map(stripInlinePhotoData);
394→  const legacySubmissions = await getLegacySubmissions();
395→  const merged = mergePointEventsWithLegacy(pointEvents, legacySubmissions);
396→  const seenExternalIds = new Set(
397→    merged
398→      .map((event) => (typeof event.externalId === "string" ? event.externalId.trim() : ""))
399→      .filter((value) => value.length > 0),
400→  );
401→  const seenPointIds = new Set(merged.map((event) => event.pointId));
402→  for (const seedEvent of BONAMOUSSADI_CURATED_SEED_EVENTS) {
403→    const externalId = typeof seedEvent.externalId === "string" ? seedEvent.externalId.trim() : "";
404→    if (externalId && seenExternalIds.has(externalId)) continue;
405→    if (seenPointIds.has(seedEvent.pointId)) continue;
406→    merged.push(seedEvent);
407→    if (externalId) seenExternalIds.add(externalId);
408→    seenPointIds.add(seedEvent.pointId);
409→  }
410→  return merged;
411→}
