 94→  useEffect(() => {
 95→    if (!adminMode) return;
 96→    const loadAdminAnalytics = async () => {
 97→      try {
 98→        setIsLoadingAdminData(true);
 99→        const scope = normalizeMapScope('global', true);
100→
101→        const pointParams = new URLSearchParams();
102→        if (scope !== 'bonamoussadi') pointParams.set('scope', scope);
103→        const pointsPath = pointParams.size > 0 ? `/api/submissions?${pointParams.toString()}` : '/api/submissions';
104→
105→        const eventParams = new URLSearchParams({ view: 'events' });
106→        if (scope !== 'bonamoussadi') eventParams.set('scope', scope);
107→        const eventsPath = `/api/submissions?${eventParams.toString()}`;
108→
109→        const [points, events] = await Promise.all([
110→          apiJson<ProjectedPoint[]>(pointsPath),
111→          apiJson<PointEvent[]>(eventsPath)
112→        ]);
113→
114→        const safePoints = Array.isArray(points) ? points : [];
115→        const safeEvents = Array.isArray(events) ? events : [];
116→
117→        const completed = safePoints.filter((point) => Array.isArray(point.gaps) && point.gaps.length === 0).length;
118→        const completion = safePoints.length > 0 ? Math.round((completed / safePoints.length) * 100) : 0;
119→        setCompletionRate(completion);
120→
121→        const now = Date.now();
122→        const activeWindowMs = 30 * 24 * 60 * 60 * 1000;
123→        const activeUsers = new Set(
124→          safeEvents
125→            .filter((event) => {
126→              const createdAt = new Date(event.createdAt).getTime();
127→              return Number.isFinite(createdAt) && now - createdAt <= activeWindowMs;
128→            })
129→            .map((event) => event.userId)
130→            .filter((userId) => typeof userId === 'string' && userId.trim().length > 0)
131→        );
132→        setActiveContributors(activeUsers.size);
133→
134→        const categoryCounts: Record<string, number> = {};
135→        for (const id of VERTICAL_IDS) categoryCounts[id] = 0;
136→        for (const event of safeEvents) {
137→          if (event.category in categoryCounts) categoryCounts[event.category] += 1;
138→        }
139→        setCategoryData(
140→          VERTICAL_IDS
141→            .filter((id) => (categoryCounts[id] ?? 0) > 0)
142→            .map((id) => ({ name: categorylabel(id as SubmissionCategory), value: categoryCounts[id], color: VERTICALS[id].color }))
143→        );
144→
145→        const categories = VERTICAL_IDS;
146→        const bucketsPerCategory = categories.map(() => [0, 0, 0, 0]);
147→        const heatWindowMs = 24 * 60 * 60 * 1000;
148→        for (const event of safeEvents) {
149→          const timestamp = new Date(event.createdAt).getTime();
150→          if (!Number.isFinite(timestamp) || now - timestamp > heatWindowMs || timestamp > now) continue;
151→          const categoryIndex = categories.indexOf(event.category);
152→          if (categoryIndex === -1) continue;
153→          const bucketIndex = Math.max(0, Math.min(3, Math.floor(new Date(timestamp).getHours() / 6)));
154→          bucketsPerCategory[categoryIndex][bucketIndex] += 1;
155→        }
156→
157→        const maxValue = Math.max(...bucketsPerCategory.flat(), 0);
158→        const toHeatLevel = (value: number): HeatLevel => {
159→          if (maxValue <= 0 || value <= 0) return 'Low';
160→          const ratio = value / maxValue;
161→          if (ratio >= 0.67) return 'High';
162→          if (ratio >= 0.34) return 'Medium';
163→          return 'Low';
164→        };
165→
166→        setHeatmap(
167→          bucketsPerCategory.map((row) => row.map((value) => toHeatLevel(value)))
168→        );
169→      } catch {
