 98→        setIsLoadingAdminData(true);
 99→        const scope = normalizeMapScope('global', true);
100→
101→        const pointParams = new URLSearchParams();
102→        if (scope !== 'bonamoussadi') pointParams.set('scope', scope);
103→        const pointsPath = pointParams.size > 0 ? `/api/submissions?${pointParams.toString()}` : '/api/submissions';
104→
105→        const eventParams = new URLSearchParams({ view: 'events' });
106→        if (scope !== 'bonamoussadi') eventParams.set('scope', scope);
107→        const eventsPath = `/api/submissions?${eventParams.toString()}`;
108→
109→        const [points, events] = await Promise.all([
110→          apiJson<ProjectedPoint[]>(pointsPath),
111→          apiJson<PointEvent[]>(eventsPath)
